mapper.select:
SELECT u.id, u.student_no AS studentNo, u.nickname, u.email, u.role, u.status, u.created_at AS createdAt, u.locked_until AS lockedUntil, COALESCE(p.post_count, 0) AS postCount FROM "user" u LEFT JOIN ( SELECT author_id, COUNT(*) AS post_count FROM post WHERE deleted = 0 GROUP BY author_id ) p ON u.id = p.author_id WHERE u.deleted = 0
AND (u.nickname ILIKE CONCAT('%', #{keyword}, '%') OR u.student_no ILIKE CONCAT('%', #{keyword}, '%'))
AND u.status = #{status}
ORDER BY u.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM "user" u WHERE u.deleted = 0
AND (u.nickname ILIKE CONCAT('%', #{keyword}, '%') OR u.student_no ILIKE CONCAT('%', #{keyword}, '%'))
AND u.status = #{status}
